import{_ as n,o as s,c as e,a2 as t}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"识别交互模式","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/deconstruction/05-identify-patterns.md","filePath":"03-interaction-design/notes/deconstruction/05-identify-patterns.md","lastUpdated":1784248569000}'),l={name:"03-interaction-design/notes/deconstruction/05-identify-patterns.md"};function i(r,a,p,d,o,h){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="识别交互模式" tabindex="-1">识别交互模式 <a class="header-anchor" href="#识别交互模式" aria-label="Permalink to &quot;识别交互模式&quot;">​</a></h1><p>交互模式是在特定任务与约束下反复出现的解决结构，包含适用问题、组成、行为、状态、无障碍语义和边界。产品拆解中的模式识别，不是给截图贴“卡片”“弹窗”标签，而是还原这个结构解决什么问题、怎样工作、何时失效。</p><h2 id="模式、组件与视觉样式" tabindex="-1">模式、组件与视觉样式 <a class="header-anchor" href="#模式、组件与视觉样式" aria-label="Permalink to &quot;模式、组件与视觉样式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>内容</th><th>示例</th></tr></thead><tbody><tr><td>交互模式</td><td>任务问题与可复用行为结构</td><td>自动完成、分步表单、撤销删除、主从详情</td></tr><tr><td>组件</td><td>可实现的界面单元及 API</td><td>Combobox、Dialog、Tabs、Button</td></tr><tr><td>页面模式</td><td>多个组件组成的任务页面结构</td><td>确认页、筛选结果页、账户设置页</td></tr><tr><td>视觉样式</td><td>外观属性</td><td>圆角卡片、阴影、品牌颜色</td></tr></tbody></table><p>同一模式可由不同组件组合实现；外观相似的组件也可能承担不同模式。例如带浮层的输入可能是自动完成、选择列表或命令面板，它们的数据、选择与键盘规则不同。</p><h2 id="模式的完整描述" tabindex="-1">模式的完整描述 <a class="header-anchor" href="#模式的完整描述" aria-label="Permalink to &quot;模式的完整描述&quot;">​</a></h2><p>识别一个模式时至少写：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模式名称</span></span>
<span class="line"><span>要解决的用户任务</span></span>
<span class="line"><span>适用前提与不适用条件</span></span>
<span class="line"><span>触发与入口</span></span>
<span class="line"><span>组成部分</span></span>
<span class="line"><span>主要行为和键盘模型</span></span>
<span class="line"><span>状态与数据规则</span></span>
<span class="line"><span>成功、失败、取消与恢复</span></span>
<span class="line"><span>响应式和无障碍要求</span></span>
<span class="line"><span>替代方案及取舍</span></span>
<span class="line"><span>证据与未确认项</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O[&quot;观察重复结构&quot;] --&gt; T[&quot;识别任务与对象&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; M[&quot;还原行为、状态和规则&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M --&gt; S[&quot;对照标准模式语义&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; B[&quot;检查边界与替代方案&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; V[&quot;实际操作验证&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>模式库是经验性指导，不是规范性标准。WAI-ARIA APG 提供组件的语义与键盘模式，但明确属于信息性指导，不是 UI 设计系统；使用时仍要评估任务、HTML 原生能力和实际辅助技术支持。</p><h2 id="从任务而不是外观开始" tabindex="-1">从任务而不是外观开始 <a class="header-anchor" href="#从任务而不是外观开始" aria-label="Permalink to &quot;从任务而不是外观开始&quot;">​</a></h2><h3 id="写出用户问题" tabindex="-1">写出用户问题 <a class="header-anchor" href="#写出用户问题" aria-label="Permalink to &quot;写出用户问题&quot;">​</a></h3><p>例如搜索成员时，用户问题可能是：</p><ul><li>已知完整邮箱，直接输入并提交；</li><li>只记得姓名一部分，需要候选建议；</li><li>必须从有限成员集合选择一个有效对象；</li><li>可以输入尚未加入系统的新邮箱。</li></ul><p>四种问题会产生不同模式：普通文本输入、自动建议、只选 Combobox 或自由输入加建议。只看到“输入框下有列表”无法判断。</p><h3 id="确定对象和值" tabindex="-1">确定对象和值 <a class="header-anchor" href="#确定对象和值" aria-label="Permalink to &quot;确定对象和值&quot;">​</a></h3><p>记录显示标签、提交值、对象 ID、多选规则、自由输入、重复项和无匹配结果。视觉上相同的选项可能提交完全不同数据。</p><h3 id="还原触发" tabindex="-1">还原触发 <a class="header-anchor" href="#还原触发" aria-label="Permalink to &quot;还原触发&quot;">​</a></h3><p>输入几个字符、聚焦、点击展开按钮、键盘命令或网络结果返回，分别会怎样打开和更新候选层？聚焦本身不应造成不可预期的上下文改变。</p><h2 id="常见模式类别" tabindex="-1">常见模式类别 <a class="header-anchor" href="#常见模式类别" aria-label="Permalink to &quot;常见模式类别&quot;">​</a></h2><h3 id="导航模式" tabindex="-1">导航模式 <a class="header-anchor" href="#导航模式" aria-label="Permalink to &quot;导航模式&quot;">​</a></h3><p>全局导航、侧栏、Tabs、面包屑、分步导航和主从详情。识别时检查目的地层级、当前项、URL、历史、直接深链和窄屏转换。</p><h3 id="输入与选择模式" tabindex="-1">输入与选择模式 <a class="header-anchor" href="#输入与选择模式" aria-label="Permalink to &quot;输入与选择模式&quot;">​</a></h3><p>表单、自动完成、日期选择、标签输入、内联编辑和文件上传。检查标签、允许值、校验时机、键盘、错误保留和服务端校验。</p><h3 id="展示与反馈模式" tabindex="-1">展示与反馈模式 <a class="header-anchor" href="#展示与反馈模式" aria-label="Permalink to &quot;展示与反馈模式&quot;">​</a></h3><p>列表、表格、卡片、空状态、骨架屏、进度、状态消息和错误摘要。检查数据关系、加载阶段、动态通知和局部失败。</p><h3 id="容器模式" tabindex="-1">容器模式 <a class="header-anchor" href="#容器模式" aria-label="Permalink to &quot;容器模式&quot;">​</a></h3><p>页面、对话框、抽屉、浮层和展开区。检查模态性、背景、焦点、关闭、URL 和响应式变化。</p><h3 id="控制与恢复模式" tabindex="-1">控制与恢复模式 <a class="header-anchor" href="#控制与恢复模式" aria-label="Permalink to &quot;控制与恢复模式&quot;">​</a></h3><p>确认、撤销、草稿、自动保存、重试、冲突解决和版本历史。检查真实副作用、幂等、保留、恢复和权威状态。</p><h2 id="对照标准时要区分层次" tabindex="-1">对照标准时要区分层次 <a class="header-anchor" href="#对照标准时要区分层次" aria-label="Permalink to &quot;对照标准时要区分层次&quot;">​</a></h2><ul><li><strong>规范要求</strong>：例如 WCAG 对键盘、名称、状态和错误的要求。</li><li><strong>平台语义</strong>：HTML 原生元素与浏览器默认行为。</li><li><strong>指导模式</strong>：APG 对复杂组件键盘与 ARIA 的建议。</li><li><strong>设计系统约定</strong>：GOV.UK 等针对具体服务建立的组件与模式。</li><li><strong>产品实现</strong>：当前界面真实行为。</li></ul><p>当前实现与模式示例不同，不自动代表错误。先判断差异是否破坏任务、平台预期、语义或可访问性。</p><h2 id="完整案例-识别-成员选择-模式" tabindex="-1">完整案例：识别“成员选择”模式 <a class="header-anchor" href="#完整案例-识别-成员选择-模式" aria-label="Permalink to &quot;完整案例：识别“成员选择”模式&quot;">​</a></h2><h3 id="具体输入与观察" tabindex="-1">具体输入与观察 <a class="header-anchor" href="#具体输入与观察" aria-label="Permalink to &quot;具体输入与观察&quot;">​</a></h3><p>项目设置中有字段“负责人”。用户输入 <code>li</code> 后出现五个候选：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>李晓 · li@example.com</span></span>
<span class="line"><span>李宁 · lining@example.com</span></span>
<span class="line"><span>Alice Li · alice@example.com</span></span>
<span class="line"><span>李晓 · li2@example.com</span></span>
<span class="line"><span>邀请 li@new.example</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>观察到：可输入自由文本；点击现有成员后显示姓名标签；输入完整新邮箱可发送邀请；按 Enter 时若高亮候选则选择，否则尝试邀请。候选从服务端异步获取。</p><h3 id="任务与对象分析" tabindex="-1">任务与对象分析 <a class="header-anchor" href="#任务与对象分析" aria-label="Permalink to &quot;任务与对象分析&quot;">​</a></h3><ul><li>字段允许“选择现有成员”和“邀请新成员”两种意图。</li><li>现有成员提交用户 ID，新邀请提交邮箱；二者必须在结果中区分。</li><li>同名成员需要邮箱或组织信息帮助识别。</li><li>自由文本只有通过邮箱规则和权限校验才能转为邀请。</li></ul><p>因此它不是普通 <code>&lt;select&gt;</code>，也不是仅允许已有值的 select-only Combobox。它接近可编辑 Combobox 加一个显式“邀请”动作，但“邀请”会产生外部副作用，不应伪装成普通选项选择。</p><h3 id="组成与状态" tabindex="-1">组成与状态 <a class="header-anchor" href="#组成与状态" aria-label="Permalink to &quot;组成与状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>部分</th><th>作用</th><th>状态</th></tr></thead><tbody><tr><td>可见标签</td><td>标识字段“负责人”</td><td>默认、错误</td></tr><tr><td>输入框</td><td>输入查询或邮箱</td><td>空、输入、焦点、无效</td></tr><tr><td>候选弹层</td><td>展示现有成员</td><td>加载、有结果、无结果、失败</td></tr><tr><td>选项</td><td>显示可区分对象</td><td>默认、高亮、选中、禁用</td></tr><tr><td>邀请动作</td><td>明确产生邀请副作用</td><td>可用、无权限、提交中、失败</td></tr><tr><td>当前值</td><td>展示已选用户或待接受邀请</td><td>已选、待邀请、冲突</td></tr></tbody></table><h3 id="键盘模型" tabindex="-1">键盘模型 <a class="header-anchor" href="#键盘模型" aria-label="Permalink to &quot;键盘模型&quot;">​</a></h3><ol><li>输入焦点保留在 Combobox；方向键在候选中改变活动项。</li><li>Enter 选择当前活动候选；Escape 关闭弹层但不清空输入。</li><li>Tab 离开组件，不应在没有明确选择时自动邀请。</li><li>候选弹层有适当角色与关联，输入暴露展开和活动项状态。</li><li>“邀请新邮箱”作为会产生副作用的明确动作，先进入复核或使用具有动作语义的按钮，不能与已有成员选项完全相同。</li></ol><h3 id="输出规范" tabindex="-1">输出规范 <a class="header-anchor" href="#输出规范" aria-label="Permalink to &quot;输出规范&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询 \`li\`：显示 4 个现有成员</span></span>
<span class="line"><span>完整有效新邮箱：显示“邀请 li@new.example”动作</span></span>
<span class="line"><span>无邀请权限：不提供邀请动作，并说明只能选择现有成员</span></span>
<span class="line"><span>服务失败：保留输入，显示“无法加载成员”，提供重试</span></span>
<span class="line"><span>选择结果：显示姓名 + 邮箱；提交保存用户 ID</span></span>
<span class="line"><span>邀请结果：显示邮箱 + “待接受”；提交保存邀请 ID</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>结果返回顺序变化：活动项按稳定对象 ID 管理，不能选择到另一人。</li><li>用户在请求返回前继续输入：丢弃旧查询结果，避免显示过期候选。</li><li>重名：结果必须有可区分辅助属性。</li><li>邀请接口超时：使用意图 ID 查询结果，避免重复邀请。</li><li>字段变为只读：仍显示负责人身份，但不暴露可编辑 Combobox 行为。</li></ul><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ol><li>使用空查询、<code>li</code>、完整邮箱、无结果和网络失败测试。</li><li>只用键盘完成搜索、选择、关闭、离开和邀请。</li><li>屏幕阅读器核对标签、展开、结果数量、活动项与已选值。</li><li>模拟快速输入和乱序响应，确认候选与查询一致。</li><li>刷新后核对现有成员 ID 与邀请状态。</li></ol><h2 id="模式对比表" tabindex="-1">模式对比表 <a class="header-anchor" href="#模式对比表" aria-label="Permalink to &quot;模式对比表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>候选模式</th><th>适用条件</th><th>不适用本案例的原因</th></tr></thead><tbody><tr><td>原生 select</td><td>少量固定选项，不需要搜索</td><td>成员多且异步，新邮箱不是固定值</td></tr><tr><td>只选 Combobox</td><td>必须选择集合中的现有对象</td><td>允许邀请新邮箱</td></tr><tr><td>自由文本加建议</td><td>任意文本都是合法最终值</td><td>最终值必须是成员 ID 或邀请记录</td></tr><tr><td>Combobox + 独立邀请动作</td><td>选择与副作用分离</td><td>符合任务，但实现与文案成本更高</td></tr></tbody></table><h2 id="可执行识别步骤" tabindex="-1">可执行识别步骤 <a class="header-anchor" href="#可执行识别步骤" aria-label="Permalink to &quot;可执行识别步骤&quot;">​</a></h2><ol><li>记录具体任务、输入、对象、权限和完成结果。</li><li>观察触发、组成、数据值和主路径。</li><li>用键盘和屏幕阅读器还原组件语义与状态。</li><li>主动制造加载、空、错误、无权限、取消和过期结果。</li><li>查找相似的官方标准、平台或设计系统模式。</li><li>区分共同机制与产品特有规则。</li><li>比较至少两个替代模式及任务取舍。</li><li>输出可实现、可验证的模式说明，而不是视觉名称。</li></ol><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>看到卡片就称为卡片模式：说明任务、对象和行为。</li><li>将组件库名称当通用定义：回到平台语义和实际结果。</li><li>只记录主路径和鼠标操作：补键盘、状态与恢复。</li><li>复制 APG 示例但忽略原生 HTML 和测试：区分指导与规范。</li><li>把相似外观的菜单、列表框与导航混用：检查值与动作语义。</li><li>发现模式后直接复用，不检查数据量、风险和小屏。</li><li>把产品特有规则包装成通用模式。</li></ul><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>从一个公开产品中识别“批量选择与操作”模式。</p><p>完成时应满足：</p><ul><li>定义任务、对象、选择范围和提交结果；</li><li>区分当前页选择、跨页选择和“全部结果”；</li><li>记录选择、部分选中、加载、空、无权限、执行中和部分成功；</li><li>说明鼠标、触控、键盘和屏幕阅读器行为；</li><li>比较工具栏、行内操作和菜单三种方案；</li><li>用固定数据验证选择数量与实际处理对象一致；</li><li>输出模式边界，不把视觉样式当结论。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Patterns</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/combobox/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Combobox Pattern</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://design-system.service.gov.uk/patterns/" target="_blank" rel="noreferrer">GOV.UK Design System：Patterns</a>（访问日期：2026-07-17）</li></ul>`,63)])])}const u=n(l,[["render",i]]);export{b as __pageData,u as default};
